let present = 0;
let absent = 0;
let late = 0;

const items = $input.all();

for (const item of items) {
  const data = item.json;

  present += data.present_days || 0;
  absent += data.absent_days || 0;
  late += data.late_days || 0;
}

return [
  {
    json: {
      employee_name: items[0].json.employee_name,
      total_present: present,
      total_absent: absent,
      total_late: late
    }
  }
];

// Generate unique invoice number with format INV-YYYYMMDD-XXXX
const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');

// Generate random 4-digit number
const randomNum = String(Math.floor(Math.random() * 10000)).padStart(4, '0');

// Create invoice number
const invoiceNumber = `INV-${year}${month}${day}-${randomNum}`;

// Return the invoice number along with existing data
return {
  ...item.json,
  invoiceNumber: invoiceNumber,
  invoiceDate: now.toISOString()
};

// Get invoice data from previous node
const items = $input.all();
const invoiceData = items[0].json;

// Check if data is nested inside 'extractedBody' (from your previous code)
const data = invoiceData.extractedBody ? invoiceData.extractedBody : invoiceData;

// Calculate subtotal by summing (quantity * price) for all items
let subtotal = 0;

if (data.items && Array.isArray(data.items)) {
  subtotal = data.items.reduce((sum, item) => {
    // Ensure we use 'quantity' and 'price' as shown in your schema
    const itemQty = parseFloat(item.quantity || 0);
    const itemPrice = parseFloat(item.price || 0);
    return sum + (itemQty * itemPrice);
  }, 0);
}

// Get tax rate from the output shown in your screenshot (taxRate: 18)
const taxRate = parseFloat(invoiceData.taxRate || 0);

// Calculate tax amount
const tax = subtotal * (taxRate / 100);

// Calculate total
const total = subtotal + tax;

// Return the data with fixed calculations
return [{
  json: {
    ...invoiceData,
    subtotal: subtotal,
    tax: tax,
    taxRate: taxRate,
    total: total
  }
}];

