const now = new Date();
const month = (now.getMonth() + 1).toString().padStart(2, '0');
const year = now.getFullYear();
const month_year = `${month}-${year}`;
return [{json: {month_year}}];

// Get employee from loop
const employee = $('LOOP - Process Each Employee').item.json;
// Get attendance (first record or empty object)
const attendanceItems = $input.all();
const attendance = attendanceItems.length > 0 ? attendanceItems[0].json : {};

const monthYear = $('CD - Calculate Month/Year').item.json.month_year;

// Salary calculation
const basicSalary = employee.basic_salary || 0;
const allowance = employee.allowance || 0;
const dailySalary = basicSalary / 30;
const absentDays = attendance.absent_days || 0;
const lateDays = attendance.late_days || 0;
const absentDeduction = absentDays * dailySalary;
const lateDeduction = lateDays * 500;
const grossSalary = basicSalary + allowance;
const totalDeductions = Math.round(absentDeduction + lateDeduction);
const netSalary = grossSalary - totalDeductions;

return {
  json: {
    employee_id: employee.employee_id,
    employee_name: employee.name,
    employee_email: employee.email,
    employee_phone: employee.phone,
    basic_salary: basicSalary,
    allowance: allowance,
    working_days: attendance.working_days || 30,
    present_days: attendance.present_days || 0,
    absent_days: absentDays,
    late_days: lateDays,
    daily_salary: Math.round(dailySalary),
    absent_deduction: Math.round(absentDeduction),
    late_deduction: lateDeduction,
    gross_salary: grossSalary,
    total_deductions: totalDeductions,
    net_salary: netSalary,
    payslip_date: new Date().toISOString().split('T')[0],
    month_year: monthYear
  }
};

